parameters.jsonBody:
={
  "model": "default",
  "messages": [
    {
      "role": "user",
      "content": "Caption from Photo task.\n\nGenerate an Instagram caption for this photo: {{ $json.name }}.\nPhoto type: food truck / slider / event photo.\n\nRespond as JSON: {\"caption\": \"...\", \"hashtags\": \"...\", \"suggested_pillar\": \"Menu Spotlight|BTS|Community|Schedule|Hype|Social Proof\", \"story_text\": \"...\"}"
    }
  ],
  "temperature": 0.7,
  "max_tokens": 500
}

parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  let aiResponse;
  try {
    const content = item.json.choices[0].message.content;
    aiResponse = JSON.parse(content);
  } catch (e) {
    aiResponse = {
      caption: item.json.choices?.[0]?.message?.content || 'Caption generation failed — please write manually',
      hashtags: '#CulinaryJEMs #GourmetSliders #AZFoodie',
      suggested_pillar: 'Menu Spotlight',
      story_text: ''
    };
  }

  const postId = 'POST-' + Date.now().toString(36).toUpperCase();
  const now = new Date();
  const scheduledDate = new Date(now.getTime() + 24 * 60 * 60 * 1000);

  results.push({
    json: {
      postId,
      status: 'draft',
      scheduledDate: scheduledDate.toISOString().split('T')[0],
      scheduledTime: '10:00',
      platform: 'both',
      contentPillar: aiResponse.suggested_pillar,
      caption: aiResponse.caption + '\n\n' + aiResponse.hashtags,
      imageUrl: item.json.webViewLink || '',
      venue: '',
      eventDate: '',
      createdAt: now.toISOString(),
      postedAt: '',
      notes: 'Auto-generated from photo: ' + (item.json.name || 'unknown'),
      storyText: aiResponse.story_text || ''
    }
  });
}

return results;

